@app.route('/logout')
def logout():
    """Logout the user and optionally redirect to the provider's logout endpoint."""
    # Get the end_session_endpoint if available
    end_session_endpoint = None
    try:
        discovery = get_oidc_discovery()
        end_session_endpoint = discovery.get('end_session_endpoint')
    except Exception:
        pass

    id_token_hint = None
    if 'tokens' in session:
        id_token_hint = session['tokens'].get('id_token')

    # Clear the session
    session.clear()

    # If the provider supports end_session, redirect there
